#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=100005;
int t,n,q,a[N],nxt[N][25],pos[25];
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>t ;
	while(t--)
	{
		cin>>n;
		memset(pos,0,sizeof(pos));
		for(int i=1;i<=n;i++)
		{
			cin>>a[i];
		}
		for(int i=n;i>=1;i--)
		{
			if(pos[a[i]]) nxt[i][0]=pos[a[i]];
			else nxt[i][0]=n+1;
			pos[a[i]]=i;
		}
		for(int i=1;i<=log2(n);i++)
		{
			for(int j=1;j<=n;j++)
			{
				if(nxt[j][i-1]<n) nxt[j][i]=nxt[nxt[j][i-1]+1][i-1];
				else nxt[j][i]=n+1;
//				cout<<j<<" "<<i<<" "<<nxt[j][i]<<"  : "<<nxt[j][i-1]<<endl;
			}
		}
//		cout<<"aaa"<<endl;
		cin>>q;
		while(q--)
		{
			int l,r;
			cin>>l>>r;
			int ans=0;
			for(int i=l;i<=r;i++)
			{
				while(i<=r&&nxt[i][0]>r)
				{
//					cout<<i<<endl;
					i++;
//					cout<<i<<endl;
					ans++;
				}
				if(i==r+1) break;
				for(int j=log2(n);j>=0;j--)
				{
					if(nxt[i][j]<=r)
					{
						i=nxt[i][j];
						break;
					}
				}
			}
			cout<<ans<<"\n";
		}
	}
	return 0;
}
